function updateHeader(){const d=today(),m=mission(); const rows=[['Passages',d.uniquePassages.length,m.passages,'mPassages'],['Exercises',d.correctExercises,m.exercises,'mExercises'],['Vocab',d.uniqueVocab.length,m.vocab,'mVocab'],['Writing',d.writingDone,m.writing,'mWriting']]; rows.forEach(([_,val,target,id])=>{$('#'+id+'Text').textContent=`${val}/${target}`; $('#'+id+'Bar').style.width=`${Math.min(100,(val/Math.max(1,target))*100)}%`}); $('#streakPill').textContent=`🔥 ${store.streak}`; $('#xpPill').textContent=`⭐ ${store.xp} XP`; $('#dailyPill').textContent=`${missionPct()}%`; $('#coachPill').textContent=coachText(); $('#todayDrop').innerHTML=`<div>${d.uniquePassages.length} unique passages</div><div>${d.repeatPassages} repeats</div><div>${d.correctExercises}/${d.attemptedExercises} correct exercises</div><div>${d.uniqueVocab.length} vocabulary seen</div><div>${d.writingDone} writing tasks</div><div>${d.listeningDone} listening tasks</div>`; }
function updateUI(){translateStatic(); updateHeader(); $('#topTitle').textContent=labelSection(state.section); $('#missionPreset').value=store.missionPreset; $('#themeSelect').value=store.theme; $('#languageSelect').value=store.lang; $('#settingsTheme').value=store.theme; $('#settingsLanguage').value=store.lang; $('#countRepeatsToggle').checked=!!store.countRepeats; $('#customPassages').value=store.missionCustom.passages; $('#customExercises').value=store.missionCustom.exercises; $('#customVocab').value=store.missionCustom.vocab; $('#customWriting').value=store.missionCustom.writing; renderGrammar(); renderVocabList(); renderWritingTask(); renderPhotoTask(); renderApp();}
function renderAll(){updateUI(); goSection(state.section)}
function goSection(sec){state.section=sec; store.lastSection=sec; saveStore(); $$('.app-section').forEach(s=>s.classList.add('hidden')); $('#section-'+sec).classList.remove('hidden'); $$('.navbtn').forEach(b=>b.classList.toggle('active',b.dataset.section===sec)); $('#topTitle').textContent=labelSection(sec); $('#sidebar').classList.remove('open')}
function switchPractice(name){state.practice=name; store.lastPractice=name; saveStore(); $$('.subbtn').forEach(b=>b.classList.toggle('active',b.dataset.practice===name)); $$('.practice-panel').forEach(p=>p.classList.add('hidden')); $('#practice-'+name).classList.remove('hidden')}
function switchVocab(mode){state.vocabMode=mode; $$('.vocabbtn').forEach(b=>b.classList.toggle('active',b.dataset.vmode===mode)); ['list','match','type'].forEach(x=>$('#vocab-'+x).classList.toggle('hidden',x!==mode))}
function switchExam(mode){state.examMode=mode; $$('.exambtn').forEach(b=>b.classList.toggle('active',b.dataset.emode===mode)); $$('.exam-panel').forEach(p=>p.classList.add('hidden')); $('#exam-'+mode).classList.remove('hidden')}

function fillFilters(){
  const types=uniqueBy(state.data.exercises,e=>e.type).map(e=>e.type).sort(); $('#exerciseTypeFilter').innerHTML='<option value="ALL">All types</option>'+types.map(t=>`<option value="${t}">${t}</option>`).join('');
  const topics=uniqueBy(state.data.vocab,v=>v.topic).map(v=>v.topic).sort(); $('#vocabTopicFilter').innerHTML='<option value="ALL">All topics</option>'+topics.map(t=>`<option>${t}</option>`).join('');
  const cats=uniqueBy(state.data.flashcards,f=>f.category).map(f=>f.category).sort(); $('#flashCategoryFilter').innerHTML='<option value="ALL">All categories</option>'+cats.map(c=>`<option>${c}</option>`).join('');
}

function poolExercises(){let arr=[...state.data.exercises]; const lvl=$('#exerciseLevelFilter').value, typ=$('#exerciseTypeFilter').value, focus=$('#exerciseFocusFilter').value; if(lvl!=='ALL') arr=arr.filter(e=>e.level===lvl); if(typ!=='ALL') arr=arr.filter(e=>e.type===typ); if(focus==='weak'){const weak=getWeakAreas().map(w=>w.type); if(weak.length) arr=arr.filter(e=>weak.includes(e.type))} return uniqueBy(arr,e=>`${e.type}|${e.question}|${e.answer}`)}
function newExercise(){const pool=poolExercises(); state.currentExercise=pool[Math.floor(Math.random()*pool.length)]||state.data.exercises[0]; $('#exerciseMeta').textContent=`${state.currentExercise.level} • ${state.currentExercise.type}`; $('#exerciseQuestion').textContent=state.currentExercise.question; $('#exerciseAnswerInput').value=''; $('#exerciseResult').textContent=''; $('#exerciseExplanation').classList.add('hidden')}
function explanationFor(type){return EXPLANATIONS[type]||EXPLANATIONS[(type||'').replace('_reason','')]||EXPLANATIONS.default}
function showExerciseAnswer(force=false){const ex=state.currentExercise, exp=explanationFor(ex.type); $('#exerciseResult').textContent=tPair(`Correct: ${ex.answer}`,`Richtig: ${ex.answer}`); $('#exerciseExplanation').innerHTML=`<strong>${tPair('Rule','Regel')}:</strong> ${store.lang==='de'?(exp.de||exp.en):(exp.en||exp.de)}<br><strong>${tPair('Example','Beispiel')}:</strong> ${exp.example||ex.hint||''}${force&&ex.hint?`<br><strong>${tPair('Hint','Hinweis')}:</strong> ${ex.hint}`:''}`; $('#exerciseExplanation').classList.remove('hidden')}
function checkExercise(){const ex=state.currentExercise, ans=$('#exerciseAnswerInput').value; const ok=norm(ans)===norm(ex.answer); today().attemptedExercises++; if(ok){today().correctExercises++; addXP(xpStep())} recordWeak(ex.type,ok); saveStore(); updateHeader(); $('#exerciseResult').textContent=ok?tPair('Correct!','Richtig!'):tPair(`Not quite. Correct: ${ex.answer}`,`Nicht ganz. Richtig: ${ex.answer}`); $('#exerciseResult').className='result '+(ok?'good':'bad'); const exp=explanationFor(ex.type); $('#exerciseExplanation').innerHTML=`<strong>${tPair('Your answer','Deine Antwort')}:</strong> ${ans||'—'}<br><strong>${tPair('Correct answer','Richtige Antwort')}:</strong> ${ex.answer}<br><strong>${tPair('Rule','Regel')}:</strong> ${store.lang==='de'?(exp.de||exp.en):(exp.en||exp.de)}<br><strong>${tPair('Example','Beispiel')}:</strong> ${exp.example||ex.hint||''}`; $('#exerciseExplanation').classList.remove('hidden')}

function typingPassages(){const lvl=$('#typingLevelFilter').value; return state.data.passages.filter(p=>lvl==='ALL'||p.level===lvl)}
function renderTypingOptions(){const options=typingPassages(); $('#typingSelect').innerHTML=options.map((p,i)=>`<option value="${i}">${p.level} • ${p.title}</option>`).join(''); loadTypingPassage()}
function currentPassage(){const list=typingPassages(); const idx=+($('#typingSelect').value||0); return list[idx]||list[0]||state.data.passages[0]}
function loadTypingPassage(){const p=currentPassage(); if(!p) return; state.currentPassage=p; $('#typingReference').value=p.german; $('#typingEnglish').value=p.english||''; $('#typingEnglishWrap').classList.toggle('hidden',!$('#typingShowEnglish').checked); $('#typingInput').value=''; $('#typingFeedback').textContent=''}
function checkTyping(){const p=currentPassage(); const typed=norm($('#typingInput').value), corr=norm(p.german); const ok=typed===corr; const ratio=Math.round((Math.max(0,1-levenshtein(typed,corr)/Math.max(1,corr.length)))*100); $('#typingFeedback').textContent=ok?tPair('Perfect match!','Perfekt!'):tPair(`Similarity: ${ratio}%`,`Ähnlichkeit: ${ratio}%`); $('#typingFeedback').className='result '+(ok?'good':'bad'); markPassageDone(`${p.level}|${p.title}`); updateHeader()}
function levenshtein(a,b){const m=[...Array(a.length+1)].map(()=>Array(b.length+1).fill(0)); for(let i=0;i<=a.length;i++)m[i][0]=i; for(let j=0;j<=b.length;j++)m[0][j]=j; for(let i=1;i<=a.length;i++)for(let j=1;j<=b.length;j++)m[i][j]=Math.min(m[i-1][j]+1,m[i][j-1]+1,m[i-1][j-1]+(a[i-1]===b[j-1]?0:1)); return m[a.length][b.length]}

function newListening(){const lvl=$('#listenLevelFilter').value; const pool=LISTENING_BANK.filter(x=>lvl==='ALL'||x.level===lvl); state.currentListen=pool[Math.floor(Math.random()*pool.length)]||LISTENING_BANK[0]; $('#listenPrompt').textContent=tPair(state.currentListen.question_en,state.currentListen.question_de); $('#listenInput').value=''; $('#listenFeedback').textContent=''; $('#listenAnswer').classList.add('hidden'); $('#listenAnswer').textContent=state.currentListen.answer}
function checkListening(){const item=state.currentListen, val=norm($('#listenInput').value); const ok=norm(item.answer)===val || item.keywords.some(k=>val.includes(norm(k))); $('#listenFeedback').textContent=ok?tPair('Good answer!','Gute Antwort!'):tPair(`Suggested answer: ${item.answer}`,`Vorschlag: ${item.answer}`); $('#listenFeedback').className='result '+(ok?'good':'bad'); recordWeak('listening',ok); today().listeningDone++; if(ok) addXP(xpStep()); saveStore(); updateHeader(); $('#listenAnswer').classList.remove('hidden')}

function sentencePool(){const lvl=$('#structureLevelFilter').value.toLowerCase(); let arr=[]; Object.entries(state.data.sentences).forEach(([k,v])=>{if(lvl==='all'||lvl===k) arr=arr.concat(v.map(x=>({...x,level:k.toUpperCase()})))}); return arr}
function newStructure(){const pool=sentencePool(); const item=pool[Math.floor(Math.random()*pool.length)]||pool[0]; state.currentStructure=item; $('#structurePrompt').textContent=tPair(`Build the sentence: ${item.en}`,`Baue den Satz: ${item.en}`); const words=shuffle(item.de.replace(/[.,!?]/g,'').split(/\s+/)); $('#structureWords').innerHTML=words.map(w=>`<button class="chip" type="button">${w}</button>`).join(''); $$('#structureWords .chip').forEach(b=>b.onclick=()=>$('#structureAnswer').value=($('#structureAnswer').value+' '+b.textContent).trim()); $('#structureAnswer').value=''; $('#structureFeedback').textContent=''; $('#structureReason').classList.add('hidden')}
function reasonForSentence(s){const x=s.toLowerCase(); let reasons=[]; if(/\bweil\b|\bdass\b|\bdamit\b|\bobwohl\b/.test(x)) reasons.push(tPair('The sentence has a subordinate clause, so the verb goes to the end there.','Der Satz hat einen Nebensatz, deshalb steht das Verb dort am Ende.')); if(/\bmit\b|\bbei\b|\bvon\b|\bzu\b|\bnach\b/.test(x)) reasons.push(tPair('A dative preposition appears here.','Hier steht eine Dativpräposition.')); if(/\bfür\b|\bohne\b|\bdurch\b|\bgegen\b|\bum\b/.test(x)) reasons.push(tPair('This preposition requires the accusative.','Diese Präposition verlangt den Akkusativ.')); if(/\bhabe\b|\bist\b|\bsind\b/.test(x)&&/ge\w+(t|en)\b/.test(x)) reasons.push(tPair('This is Perfekt: auxiliary verb + participle.','Das ist Perfekt: Hilfsverb + Partizip II.')); if(/\bab\b$/.test(x)) reasons.push(tPair('This looks like a separable verb, so the prefix moves to the end.','Das ist ein trennbares Verb, deshalb steht die Vorsilbe am Ende.')); if(/\bdem\b|\bder\b|\bden\b/.test(x)) reasons.push(tPair('Watch the article: the form often shows the case.', 'Achte auf den Artikel: Die Form zeigt oft den Fall.')); return reasons.join(' ')||tPair('Focus on verb position, articles, and word order.', 'Achte auf Verbposition, Artikel und Wortstellung.')}
function showStructure(force=false){const sent=state.currentStructure.de; const ok=norm($('#structureAnswer').value)===norm(sent); if(force||!ok) $('#structureFeedback').textContent=tPair(`Correct sentence: ${sent}`,`Richtiger Satz: ${sent}`); $('#structureFeedback').className='result '+(ok?'good':'bad'); $('#structureReason').innerHTML=`<strong>${tPair('Why?','Warum?')}</strong> ${reasonForSentence(sent)}`; $('#structureReason').classList.remove('hidden'); if(ok){today().correctExercises++; today().attemptedExercises++; addXP(xpStep()); saveStore(); updateHeader()}}
function checkStructure(){const sent=state.currentStructure.de; const ok=norm($('#structureAnswer').value)===norm(sent); recordWeak('sentence_structure',ok); showStructure(false)}

function fillWritingTasks(){ $('#writingTaskSelect').innerHTML=WRITING_TASKS.map((t,i)=>`<option value="${i}">${t.title}</option>`).join(''); $('#photoTaskSelect').innerHTML=PHOTO_TASKS.map((t,i)=>`<option value="${i}">${t.title}</option>`).join('') }
function renderWritingTask(){ const task=WRITING_TASKS[+$('#writingTaskSelect').value||0]; state.currentWriting=task; $('#writingPrompt').textContent=store.lang==='de'&&task.prompt_de?task.prompt_de:task.prompt_en; $('#writingInput').value=''; $('#writingFeedback').textContent=''; $('#writingSample').classList.add('hidden'); $('#writingSample').textContent=task.sample; const show=task.type==='photo'; $('#writingPhotoWrap').classList.toggle('hidden',!show); if(show){$('#writingPhoto').src=task.src||PHOTO_TASKS[0].src;}} 
function checkWriting(){const text=$('#writingInput').value.trim(); const wc=text?text.split(/\s+/).length:0; const sample=state.currentWriting.sample; const needed=state.currentWriting.type==='photo'?40:25; const good=wc>=needed; $('#writingFeedback').textContent=good?tPair(`Good start. Word count: ${wc}`,`Guter Anfang. Wortzahl: ${wc}`):tPair(`Write a bit more. Word count: ${wc}`,`Schreibe noch etwas mehr. Wortzahl: ${wc}`); $('#writingFeedback').className='result '+(good?'good':'bad'); if(good){today().writingDone++; addXP(xpStep()); saveStore(); updateHeader()} $('#writingSample').textContent=sample}

function vocabPool(){let arr=[...state.data.vocab]; const lvl=$('#vocabLevelFilter').value, topic=$('#vocabTopicFilter').value, s=norm($('#vocabSearch').value), diff=$('#vocabDifficultOnly').checked; if(lvl!=='ALL') arr=arr.filter(v=>v.level===lvl); if(topic!=='ALL') arr=arr.filter(v=>v.topic===topic); if(diff) arr=arr.filter(v=>store.difficultWords.includes(v.de)); if(s) arr=arr.filter(v=>norm(v.de).includes(s)||norm(v.en).includes(s)||norm(v.example_de||'').includes(s)||norm(v.example_en||'').includes(s)); return arr}
function renderVocabList(){const list=vocabPool(); $('#vocabListWrap').innerHTML=list.slice(0,300).map(v=>`<div class="vocab-item"><div class="vocab-top"><div><div class="vocab-word">${v.de}</div><div class="muted">${v.en} • ${v.level} • ${v.topic||'General'}</div></div><button class="ghost diff-btn" data-word="${escapeAttr(v.de)}">${store.difficultWords.includes(v.de)?'★':'☆'}</button></div><div class="vocab-example"><strong>DE:</strong> ${v.example_de||'—'}<br><strong>EN:</strong> ${v.example_en||'—'}</div></div>`).join('')||`<div class="note-block">${tPair('No vocabulary found for this filter.','Kein Wortschatz für diesen Filter gefunden.')}</div>`; $$('.diff-btn').forEach(b=>b.onclick=()=>toggleDifficult(unescapeAttr(b.dataset.word)))}
function toggleDifficult(word){if(store.difficultWords.includes(word)) store.difficultWords=store.difficultWords.filter(w=>w!==word); else store.difficultWords.push(word); saveStore(); renderVocabList(); renderApp()}
function escapeAttr(s){return s.replace(/"/g,'&quot;')} function unescapeAttr(s){return s.replace(/&quot;/g,'"')}
function newMatch(){const items=shuffle(state.data.vocab).slice(0,6); state.matchItems=items; $('#matchDe').innerHTML=items.map((v,i)=>`<button class="match-btn" data-side="de" data-idx="${i}">${v.de}</button>`).join(''); $('#matchEn').innerHTML=shuffle(items.map((v,i)=>({i,en:v.en}))).map(v=>`<button class="match-btn" data-side="en" data-idx="${v.i}">${v.en}</button>`).join(''); state.sel={}; $('#matchFeedback').textContent=''; $$('.match-btn').forEach(b=>b.onclick=onMatchClick)}
function onMatchClick(e){const btn=e.currentTarget, side=btn.dataset.side, idx=btn.dataset.idx; $$(`.match-btn[data-side="${side}"]`).forEach(x=>x.classList.remove('selected')); btn.classList.add('selected'); state.sel[side]=idx; if(state.sel.de!=null&&state.sel.en!=null){const ok=state.sel.de===state.sel.en; const word=state.matchItems[+state.sel.de]; $('#matchFeedback').textContent=ok?tPair('Match!','Treffer!'):tPair('Not a match.','Passt nicht.'); $('#matchFeedback').className='result '+(ok?'good':'bad'); if(ok) addVocabSeen(word.de); state.sel={}; setTimeout(newMatch, ok?500:800)}}
function newTypeWord(){state.currentWord=state.data.vocab[Math.floor(Math.random()*state.data.vocab.length)]; $('#typeWordMeta').textContent=`${state.currentWord.level} • ${state.currentWord.topic||'General'}`; $('#typeWordPrompt').textContent=tPair(`Type the German word for: ${state.currentWord.en}`,`Schreibe das deutsche Wort für: ${state.currentWord.en}`); $('#typeWordInput').value=''; $('#typeWordFeedback').textContent=''}
function showTypeWord(force=false){const w=state.currentWord; const ok=!force&&norm($('#typeWordInput').value)===norm(w.de); $('#typeWordFeedback').textContent=ok?tPair('Correct!','Richtig!'):tPair(`Correct: ${w.de}`,`Richtig: ${w.de}`); $('#typeWordFeedback').className='result '+(ok?'good':'bad'); if(ok) addVocabSeen(w.de)}
function checkTypeWord(){showTypeWord(false)}

function renderGrammar(){const s=norm($('#grammarSearch').value); const notesEntries=Object.entries(state.data.notes).filter(([k,v])=>!s||norm(k).includes(s)||norm(String(v)).includes(s)); $('#grammarWrap').innerHTML=`${masterTablesHtml()}${notesEntries.slice(0,120).map(([k,v])=>`<div class="grammar-section"><h4>${k.replaceAll('_',' ')}</h4><div class="note-block">${String(v).replace(/\n/g,'<br>')}</div></div>`).join('')}<div class="grammar-section"><h4>Reference</h4><div class="media-wrap"><img src="assets/grammar_reference.png" alt="Grammar reference"></div></div>`}
function tableWrap(title,html){return `<div class="grammar-section"><h4>${title}</h4><div class="grammar-table-wrap">${html}</div></div>`}
function masterTablesHtml(){
  return [
    tableWrap('Definite / Indefinite / Kein',`<table class="grammar-table"><tr><th>Case</th><th>der</th><th>die</th><th>das</th><th>ein</th><th>eine</th><th>ein</th><th>kein</th><th>keine</th><th>kein</th></tr><tr><td>Nominativ</td><td>der</td><td>die</td><td>das</td><td>ein</td><td>eine</td><td>ein</td><td>kein</td><td>keine</td><td>kein</td></tr><tr><td>Akkusativ</td><td>den</td><td>die</td><td>das</td><td>einen</td><td>eine</td><td>ein</td><td>keinen</td><td>keine</td><td>kein</td></tr><tr><td>Dativ</td><td>dem</td><td>der</td><td>dem</td><td>einem</td><td>einer</td><td>einem</td><td>keinem</td><td>keiner</td><td>keinem</td></tr><tr><td>Genitiv</td><td>des</td><td>der</td><td>des</td><td>eines</td><td>einer</td><td>eines</td><td>keines</td><td>keiner</td><td>keines</td></tr></table>`),
    tableWrap('Personal / Reflexive Pronouns',`<table class="grammar-table"><tr><th>Case</th><th>ich</th><th>du</th><th>er</th><th>sie</th><th>es</th><th>wir</th><th>ihr</th><th>sie/Sie</th></tr><tr><td>Nominativ</td><td>ich</td><td>du</td><td>er</td><td>sie</td><td>es</td><td>wir</td><td>ihr</td><td>sie / Sie</td></tr><tr><td>Akkusativ</td><td>mich</td><td>dich</td><td>ihn</td><td>sie</td><td>es</td><td>uns</td><td>euch</td><td>sie / Sie</td></tr><tr><td>Dativ</td><td>mir</td><td>dir</td><td>ihm</td><td>ihr</td><td>ihm</td><td>uns</td><td>euch</td><td>ihnen / Ihnen</td></tr></table><table class="grammar-table"><tr><th>Reflexive</th><th>Akk</th><th>Dat</th></tr><tr><td>ich</td><td>mich</td><td>mir</td></tr><tr><td>du</td><td>dich</td><td>dir</td></tr><tr><td>er/sie/es</td><td>sich</td><td>sich</td></tr><tr><td>wir</td><td>uns</td><td>uns</td></tr><tr><td>ihr</td><td>euch</td><td>euch</td></tr><tr><td>sie/Sie</td><td>sich</td><td>sich</td></tr></table>`),
    tableWrap('Possessives',`<table class="grammar-table"><tr><th>Base</th><th>masc nom</th><th>fem nom</th><th>neut nom</th><th>plural nom</th><th>masc akk</th><th>dativ masc</th></tr><tr><td>mein-</td><td>mein Vater</td><td>meine Mutter</td><td>mein Kind</td><td>meine Freunde</td><td>meinen Vater</td><td>meinem Vater</td></tr><tr><td>dein-</td><td>dein Job</td><td>deine Firma</td><td>dein Auto</td><td>deine Kollegen</td><td>deinen Job</td><td>deinem Job</td></tr><tr><td>sein-/ihr-</td><td>sein Termin</td><td>ihre Wohnung</td><td>sein Problem</td><td>ihre Fragen</td><td>seinen Termin</td><td>seinem Termin</td></tr></table>`),
    tableWrap('Adjective Endings',`<table class="grammar-table"><tr><th>Pattern</th><th>Nominativ</th><th>Akkusativ</th><th>Dativ</th></tr><tr><td>definite article</td><td>der gute Mann</td><td>den guten Mann</td><td>dem guten Mann</td></tr><tr><td>indefinite article</td><td>ein guter Mann</td><td>einen guten Mann</td><td>einem guten Mann</td></tr><tr><td>no article</td><td>guter Kaffee</td><td>guten Kaffee</td><td>gutem Kaffee</td></tr></table>`),
    tableWrap('Prepositions & Da-words',`<table class="grammar-table"><tr><th>Akkusativ</th><th>Dativ</th><th>Wechselpräpositionen</th><th>Da-word</th><th>Example</th></tr><tr><td>für, ohne, durch, gegen, um</td><td>mit, nach, bei, von, zu</td><td>in, an, auf, unter, über, vor, hinter, neben, zwischen</td><td>darauf</td><td>Ich warte darauf.</td></tr><tr><td>—</td><td>—</td><td>Movement = Akk / location = Dat</td><td>daran</td><td>Ich denke daran.</td></tr><tr><td>—</td><td>—</td><td>—</td><td>damit</td><td>Ich fahre damit.</td></tr><tr><td>—</td><td>—</td><td>—</td><td>davon</td><td>Ich träume davon.</td></tr><tr><td>—</td><td>—</td><td>—</td><td>dazu</td><td>Was sagst du dazu?</td></tr></table>`),
    tableWrap('Connectors & Sentence Signals',`<table class="grammar-table"><tr><th>Word</th><th>Meaning</th><th>Verb position</th><th>Example</th></tr><tr><td>weil</td><td>because</td><td>end</td><td>..., weil ich krank bin.</td></tr><tr><td>dass</td><td>that</td><td>end</td><td>Ich denke, dass er kommt.</td></tr><tr><td>damit</td><td>so that</td><td>end</td><td>Ich lerne, damit ich bestehe.</td></tr><tr><td>obwohl</td><td>although</td><td>end</td><td>..., obwohl es regnet.</td></tr><tr><td>deshalb</td><td>therefore</td><td>main clause V2</td><td>Es regnet. Deshalb bleibe ich zu Hause.</td></tr></table>`)
  ].join('')
}

function flashPool(){const c=$('#flashCategoryFilter').value; return state.data.flashcards.filter(f=>c==='ALL'||f.category===c)}
function nextFlash(){const pool=flashPool(); state.currentFlash=pool[Math.floor(Math.random()*pool.length)]||pool[0]; state.flashFront=true; $('#flashCard').textContent=state.currentFlash?.front||'—'}
function flipFlash(){if(!state.currentFlash) return; state.flashFront=!state.flashFront; $('#flashCard').textContent=state.flashFront?state.currentFlash.front:state.currentFlash.back}

function conjPool(){const lvl=$('#conjLevelFilter').value; return state.data.conjugation.filter(v=>lvl==='ALL'||v.level===lvl)}
function newConj(){const pool=conjPool(); const verb=pool[Math.floor(Math.random()*pool.length)]||pool[0]; const pronouns=Object.keys(verb.forms); const pron=pronouns[Math.floor(Math.random()*pronouns.length)]; state.currentConj={verb,pron,answer:verb.forms[pron]}; $('#conjQuestion').textContent=`${verb.infinitive} (${verb.english}) → ${pron} = ?`; $('#conjInput').value=''; $('#conjFeedback').textContent=''; $('#conjReveal').classList.add('hidden')}
function showConj(){const c=state.currentConj; $('#conjReveal').innerHTML=`<strong>${tPair('Answer','Antwort')}:</strong> ${c.pron} ${c.answer}<br><strong>${tPair('All forms','Alle Formen')}:</strong> ${Object.entries(c.verb.forms).map(([k,v])=>`${k} ${v}`).join(' • ')}`; $('#conjReveal').classList.remove('hidden')}
function checkConj(){const ok=norm($('#conjInput').value)===norm(state.currentConj.answer); $('#conjFeedback').textContent=ok?tPair('Correct!','Richtig!'):tPair(`Not quite. ${state.currentConj.pron} ${state.currentConj.answer}`,`Nicht ganz. ${state.currentConj.pron} ${state.currentConj.answer}`); $('#conjFeedback').className='result '+(ok?'good':'bad'); if(ok){today().correctExercises++; today().attemptedExercises++; addXP(xpStep()); saveStore(); updateHeader()} recordWeak('conjugation',ok); showConj()}

function examBasePool(level){if(level==='freestyle') return state.data.exercises.filter(e=>['A1','A2','B1','B2'].includes(e.level)); return state.data.exercises.filter(e=>e.level===level || (level==='A1'&&e.level==='A2'))}
function startExam(){const level=$('#examLevel').value; const pool=shuffle(uniqueBy(examBasePool(level),e=>`${e.type}|${e.question}|${e.answer}`)); const questions=pool.slice(0,12).map((q,i)=>({...q,points:i<8?3:4})); const passage=(level==='freestyle'?shuffle(state.data.passages).find(p=>['A2','B1','B2'].includes(p.level)):shuffle(state.data.passages).find(p=>p.level===level)||state.data.passages[0]); const writing=level==='A1'?WRITING_TASKS[0]:level==='A2'?WRITING_TASKS[2]:level==='B1'?PHOTO_TASKS[0]:WRITING_TASKS[1]; state.currentExam={level,questions,passage,writing}; $('#examWrap').innerHTML=`<div class="note-block"><strong>${tPair('Reading passage','Lesetext')}:</strong><br><strong>${passage.title}</strong><br>${passage.german}</div>`+questions.map((e,i)=>`<div class="note-block"><div><strong>Q${i+1} (${e.points}pt)</strong> ${e.question}</div><input class="exam-input" data-i="${i}" type="text"></div>`).join('')+`<div class="note-block"><strong>${tPair('Writing (15 pt)','Schreiben (15 P)')}</strong><br>${store.lang==='de'?(writing.prompt_de||writing.prompt_en):(writing.prompt_en||writing.prompt_de)}<textarea id="examWriting"></textarea></div>`; $('#examResult').textContent=''}
function estimateLevel(score){if(score>=50) return 'B2'; if(score>=40) return 'B1'; if(score>=28) return 'A2'; return 'A1'}
function finishExam(){if(!state.currentExam) return; let pts=0, max=0; state.currentExam.questions.forEach((e,i)=>{max+=e.points; if(norm($(`.exam-input[data-i="${i}"]`)?.value||'')===norm(e.answer)) pts+=e.points}); max+=15; const words=($('#examWriting').value||'').trim().split(/\s+/).filter(Boolean).length; if(words>=35) pts+=15; const result=`${tPair('Result','Ergebnis')}: ${pts}/${max} • ${tPair('Estimated level','Geschätztes Niveau')}: ${estimateLevel(pts)}`; $('#examResult').textContent=result; $('#examResult').className='result '+(pts>=Math.round(max*0.6)?'good':'bad')}

function renderPhotoTask(){const task=PHOTO_TASKS[+$('#photoTaskSelect').value||0]; state.currentPhoto=task; $('#photoExamImage').src=task.src; $('#photoExamPrompt').textContent=store.lang==='de'?task.prompt_de:task.prompt_en; $('#photoExamInput').value=''; $('#photoExamFeedback').textContent=''; $('#photoExamSample').textContent=task.sample; $('#photoExamSample').classList.add('hidden')}
function checkPhotoExam(){const text=$('#photoExamInput').value.trim(); const wc=text.split(/\s+/).filter(Boolean).length; const hasOpinion=/meiner meinung nach|ich finde|ich denke/.test(text.toLowerCase()); const good=wc>=40; $('#photoExamFeedback').textContent=good?tPair(`Good exam-style response. ${wc} words${hasOpinion?', opinion phrase used':''}.`,`Gute prüfungsnahe Antwort. ${wc} Wörter${hasOpinion?', Meinungssatz benutzt':''}.`):tPair(`Write more detail. ${wc} words.`,`Schreibe ausführlicher. ${wc} Wörter.`); $('#photoExamFeedback').className='result '+(good?'good':'bad')}

function qaPool(mode){return state.data.exercises.filter(e=>e.type=== (mode==='answer'?'question_to_answer':'answer_to_question'))}
function newQA(){const mode=$('#qaMode').value; state.currentQA=qaPool(mode)[Math.floor(Math.random()*qaPool(mode).length)]||qaPool(mode)[0]; $('#qaPrompt').textContent=state.currentQA.question; $('#qaInput').value=''; $('#qaFeedback').textContent=''; $('#qaExplanation').classList.add('hidden')}
function showQA(){const item=state.currentQA; const exp=explanationFor(item.type); $('#qaExplanation').innerHTML=`<strong>${tPair('Model answer','Musterantwort')}:</strong> ${item.answer}<br><strong>${tPair('Why?','Warum?')}</strong> ${store.lang==='de'?(exp.de||exp.en):(exp.en||exp.de)}`; $('#qaExplanation').classList.remove('hidden')}
function checkQA(){const item=state.currentQA; const val=$('#qaInput').value; const ok=norm(val)===norm(item.answer); $('#qaFeedback').textContent=ok?tPair('Good answer!','Gute Antwort!'):tPair(`Suggested answer: ${item.answer}`,`Vorschlag: ${item.answer}`); $('#qaFeedback').className='result '+(ok?'good':'bad'); recordWeak(item.type,ok); showQA()}

function newLid(){state.currentLid=shuffle(LID_QUESTIONS)[0]; $('#lidQuestion').textContent=state.currentLid.q; $('#lidMeta').textContent=tPair('Large practice bank • democracy, history, society','Großer Übungspool • Demokratie, Geschichte, Gesellschaft'); $('#lidFeedback').textContent=''; $('#lidExplain').classList.add('hidden'); $('#lidChoices').innerHTML=state.currentLid.choices.map((c,i)=>`<button class="chip lid-choice" data-i="${i}">${c}</button>`).join(''); $$('.lid-choice').forEach(b=>b.onclick=()=>checkLid(+b.dataset.i))}
function checkLid(i){const ok=i===state.currentLid.a; $$('.lid-choice').forEach((b,idx)=>{b.classList.toggle('correct-option',idx===state.currentLid.a); if(idx===i && !ok) b.classList.add('wrong-option')}); $('#lidFeedback').textContent=ok?tPair('Correct!','Richtig!'):tPair('Not quite.','Nicht ganz.'); $('#lidFeedback').className='result '+(ok?'good':'bad'); $('#lidExplain').innerHTML=state.currentLid.ex; $('#lidExplain').classList.remove('hidden'); if(ok) addXP(1)}
function showLidAnswer(){checkLid(state.currentLid.a)}

function renderApp(){const weak=getWeakAreas().slice(0,6).map(w=>`<div>• ${w.type}</div>`).join('')||'<div>• None yet</div>'; $('#weakAreaText').innerHTML=`<strong>${tPair('Weak areas','Schwache Bereiche')}</strong>${weak}`; $('#aboutText').innerHTML=`<div><strong>${tPair('App details','App-Details')}</strong></div><div>Passages: ${state.data.passages.length}</div><div>Exercises: ${state.data.exercises.length}</div><div>Words: ${state.data.vocab.length}</div><div>Verbs: ${state.data.conjugation.length}</div><div>${tPair('Leben in Deutschland practice in this app is inspired by the official BAMF test structure and topics.','Das Leben-in-Deutschland-Training in dieser App orientiert sich an der offiziellen BAMF-Struktur und den Themen.')}</div><div>${tPair('Counts stay here, not on the main screen.','Die Mengen stehen hier und nicht auf der Startansicht.')}</div>`}

init();
